        long g = 5;     // publicly shared base

        long a = 6;     // Alice's secret
        long b = 15;    // Bob's secret

        long A = modPow(g, a, p);
        System.out.println("Alice sends: " + A);

        long B = modPow(g, b, p);
        System.out.println("Bob sends: " + B);

        long aliceSecret = modPow(B, a, p);
